package org.apache.spark.sql.odps

import org.scalatest.funsuite.AnyFunSuite

class OdpsUtilsSuite extends AnyFunSuite {

  test("typeStr2Type array") {
    val odpsTypeStr = "ARRAY<STRUCT<`index`:BIGINT,`spent_transaction_hash`:STRING,`spent_output_index`:BIGINT,`script_asm`:STRING,`script_hex`:STRING,`sequence`:BIGINT,`required_signatures`:BIGINT,`type`:STRING,`addresses`:ARRAY<STRING>,`value`:DECIMAL(38,8),a:char(44),b:varchar(255)>>"
    val (dataType, _) = OdpsUtils.typeStr2Type(
      odpsTypeStr,
      false)
    assert(odpsTypeStr.toLowerCase === dataType.catalogString)
  }

  test("typeStr2Type struct") {
    val odpsTypeStr = "STRUCT<campaign_id:STRING,name:STRING,version:INT,valid_from:TIMESTAMP,valid_until:TIMESTAMP,status:STRING,metadata:STRING,attributes:STRING,created_at:TIMESTAMP,value:DECIMAL(38,8),updated_at:TIMESTAMP,target_date:STRUCT<year:INT,month:INT,day:INT,value2:DECIMAL(38,8)>,campaign_type:STRING>"
    val (dataType, _) = OdpsUtils.typeStr2Type(
      odpsTypeStr,
      true)
    assert(odpsTypeStr.toLowerCase === dataType.catalogString)
  }

